dark.customCSS:
:root {
  --primary-text: #ffc0db;
  --primary-pink: #ff69b4;
  --primary-bg: #2a1020;
  --hover-bg: #3d1a2e;
}

* {
  color: var(--primary-text) !important;
}

#send-message-button {
  background-color: var(--primary-pink) !important;
}

#sidebar {
  background-color: var(--primary-bg) !important;
}

#sidebar > div *:hover {
  background-color: var(--hover-bg) !important;
}

[aria-label="Voice mode"] {
  background-color: var(--primary-pink) !important;
}

.tippy-content {
  background-color: var(--primary-pink) !important;
  border-color: var(--primary-pink) !important;
}

.tippy-box {
  background-color: var(--primary-pink) !important;
  border-color: var(--primary-pink) !important;
}

button[type="submit"] {
  background-color: var(--primary-pink) !important;
}

[role="switch"][aria-checked="true"] {
  background-color: var(--primary-pink) !important;
}

button.px-3\.5.py-1\.5.text-sm.font-medium.bg-black.hover\:bg-gray-900.text-white.dark\:bg-white.dark\:text-black.dark\:hover\:bg-gray-100.transition.rounded-full {
  background-color: var(--primary-pink) !important;
}
/* Dark modes: burgundy text vanishes on dark surfaces — flip the chat side
   to a soft pink while the light-pink sidebar keeps its burgundy text
   (id selector outranks the mode override). */
html.dark .app * {
  color: #ffd6e7 !important;
}

#sidebar, #sidebar * {
  color: #8b1538 !important;
}

dark.canvasScript:
let canvas, ctx, W, H;
const particles = [];
const MAX = 80;

function createParticle() {
  return {
    x: Math.random() * W,
    y: Math.random() * H,
    r: 2 + Math.random() * 6,
    dx: (Math.random() - 0.5) * 0.3,
    dy: -0.2 - Math.random() * 0.3,
    alpha: 0.3 + Math.random() * 0.4,
    color: ["#ff69b4", "#ff85c8", "#ff3399", "#cc2277"][Math.random() * 4 | 0]
  };
}

function init(c, w, h) {
  canvas = c; ctx = c.getContext('2d'); W = w; H = h;
  particles.length = 0;
  for (let i = 0; i < MAX; i++) particles.push(createParticle());
}

function draw() {
  ctx.fillStyle = 'rgba(30, 10, 20, 0.06)';
  ctx.fillRect(0, 0, W, H);
  for (let i = 0; i < particles.length; i++) {
    const p = particles[i];
    p.x += p.dx; p.y += p.dy;
    if (p.y + p.r < 0 || p.x < -10 || p.x > W + 10) {
      const np = createParticle();
      np.y = H + np.r;
      particles[i] = np;
      continue;
    }
    ctx.beginPath();
    ctx.arc(p.x, p.y, p.r, 0, 6.283);
    ctx.fillStyle = p.color;
    ctx.globalAlpha = p.alpha;
    ctx.fill();
    ctx.globalAlpha = 1;
  }
  requestAnimationFrame(draw);
}

setInterval(() => { self.postMessage({ type: 'heartbeat' }); }, 1000);

self.onmessage = function(e) {
  const { type, canvas: c, width, height } = e.data;
  switch (type) {
    case 'init': init(c, width, height); draw(); break;
    case 'resize': W = width; H = height; if (canvas) { canvas.width = W; canvas.height = H; } break;
    case 'mousemove': break;
  }
};

